<?php declare(strict_types=1);require __DIR__.'/bootstrap.php';$pageTitle='Licenses';require VP3_ROOT.'/includes/account-header.php';$rows=[];if(vp3_db_available()){$stmt=vp3_db()->prepare('SELECT l.license_uuid,l.license_key_prefix,l.license_fingerprint,l.edition,l.status,l.max_activations,l.activation_count,l.expires_at,l.updates_until,p.name product_name,pp.name plan_name FROM licenses l JOIN products p ON p.id=l.product_id JOIN product_plans pp ON pp.id=l.plan_id WHERE l.customer_id=? ORDER BY l.id DESC');$stmt->execute([$customer['id']]);$rows=$stmt->fetchAll();}?><h1>Product licenses</h1><p class="helper">Full license keys are shown only at issuance. VP3 stores a secure hash, safe prefix, and fingerprint.</p><div class="table-wrap"><table class="table"><thead><tr><th>Product</th><th>Plan</th><th>Safe identifier</th><th>Status</th><th>Activations</th><th>Updates</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=vp3_e($r['product_name'])?></td><td><?=vp3_e($r['plan_name'])?></td><td><code><?=vp3_e($r['license_key_prefix'])?>…</code><br><small><?=vp3_e($r['license_fingerprint'])?></small></td><td><span class="badge <?=vp3_e($r['status'])?>"><?=vp3_e($r['status'])?></span></td><td><?=(int)$r['activation_count']?> / <?=(int)$r['max_activations']?></td><td><?=vp3_e((string)$r['updates_until'])?></td></tr><?php endforeach;?><?php if(!$rows):?><tr><td colspan="6">No licenses have been issued.</td></tr><?php endif;?></tbody></table></div><?php require VP3_ROOT.'/includes/account-footer.php';?>